<style>:root{--bg:#080d0b;--card:#111d17;--green:#22c55e;--text:#ecfdf5;--border:rgba(34,197,94,0.12)}body{font-family:'Inter',sans-serif;background:var(--bg);color:var(--text);margin:0;display:flex}.sidebar{width:250px;background:#080f0b;padding:20px}.main{flex:1;padding:30px}.card{background:var(--card);padding:20px;border-radius:12px;border:1px solid var(--border)}.nav-link{display:block;padding:12px;margin:8px 0;background:var(--card);color:var(--text);border-radius:8px;text-decoration:none}.nav-link:hover{background:var(--green);color:var(--bg)}.dot{width:12px;height:12px;background:var(--green);border-radius:50%;animation:pulse 2s infinite}@keyframes pulse{0%,100%{opacity:1}50%{opacity:.5}}.messages{height:400px;overflow-y:auto;margin-bottom:15px;padding:15px;background:var(--bg);border-radius:8px}.msg{margin:10px 0}.msg.user{text-align:right}.msg-content{display:inline-block;padding:10px 15px;border-radius:8px;max-width:70%}.msg.user .msg-content{background:var(--green);color:var(--bg)}.msg.bot .msg-content{background:var(--card);border:1px solid var(--border)}</style></head><body>
