<div class="main"><h1 style="font-family:'Space Grotesk',sans-serif;color:var(--green)">JARVIS AGI Assistant</h1>
<div class="card"><div style="display:flex;align-items:center;gap:10px;margin-bottom:15px"><div class="dot"></div><span>AGI Online - Port 5052</span></div>
<div class="messages"><div class="msg bot"><div class="msg-content">Hello Richard! I'm JARVIS AGI, your poultry farm assistant. How can I help?</div></div></div>
<div style="display:flex;gap:10px"><input id="input" type="text" placeholder="Ask about your farm..." style="flex:1;padding:12px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--text)"><button onclick="send()" style="padding:12px 24px;border:none;border-radius:8px;background:var(--green);color:var(--bg);font-weight:600;cursor:pointer">Send</button></div></div></div>
<script>function send(){const i=document.getElementById('input');if(!i.value.trim())return;const m=document.querySelector('.messages');m.innerHTML+='<div class=\"msg user\"><div class=\"msg-content\">'+i.value+'</div></div>';i.value='';m.scrollTop=m.scrollHeight;setTimeout(()=>{m.innerHTML+='<div class=\"msg bot\"><div class=\"msg-content\">Connect to port 5052 for live AGI response.</div></div>';m.scrollTop=m.scrollHeight},1000)}</script></body></html>